mapper.select:
select coupon_template_id as couponTemplateId, coupon_name as couponName, coupon_type as couponType, face_value as faceValue, discount_rate as discountRate, threshold_amount as thresholdAmount, applicable_role as applicableRole, applicable_contest_ids as applicableContestIds, valid_days as validDays, valid_start as validStart, valid_end as validEnd, stack_rule as stackRule, status, remark, create_time as createTime, update_time as updateTime from jst_coupon_template
del_flag = '0'
and coupon_name like concat('%', #{couponName}, '%')
and coupon_type = #{couponType}
and status = #{status}
order by coupon_template_id desc

select coupon_template_id as couponTemplateId, coupon_name as couponName, coupon_type as couponType, face_value as faceValue, discount_rate as discountRate, threshold_amount as thresholdAmount, applicable_role as applicableRole, applicable_contest_ids as applicableContestIds, valid_days as validDays, valid_start as validStart, valid_end as validEnd, stack_rule as stackRule, status from jst_coupon_template
del_flag = '0' and status = 1 and (applicable_role = #{applicableRole} or applicable_role = 'all' or applicable_role = 'both') and (valid_start is null or valid_start <= #{now}) and (valid_end is null or valid_end >= #{now})
and (stack_rule != 'once' or coupon_template_id not in
#{templateId}
)
order by coupon_template_id desc

select coupon_template_id as couponTemplateId, coupon_name as couponName, coupon_type as couponType, face_value as faceValue, discount_rate as discountRate, threshold_amount as thresholdAmount, applicable_role as applicableRole, applicable_contest_ids as applicableContestIds, valid_days as validDays, valid_start as validStart, valid_end as validEnd, stack_rule as stackRule, status from jst_coupon_template
del_flag = '0' and status = 1 and coupon_template_id in
#{templateId}
and (applicable_role = #{applicableRole} or applicable_role = 'all' or applicable_role = 'both') and (valid_start is null or valid_start <= #{now}) and (valid_end is null or valid_end >= #{now})
and (stack_rule != 'once' or coupon_template_id not in
#{excludeTemplateId}
)
order by coupon_template_id desc

mapper.update:
update jst_coupon_template
set status = #{status},
    update_by = #{updateBy},
    update_time = #{updateTime}
where coupon_template_id = #{couponTemplateId}
  and del_flag = '0'

update jst_coupon_template
set del_flag = '2',
    update_by = #{updateBy},
    update_time = #{updateTime}
where coupon_template_id = #{couponTemplateId}
  and del_flag = '0'
